import os
import json
import argparse
import heapq
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()

    for step in range(max_steps):
        try:
            neighbors = obs['neighbors']
            nodes = obs['nodes']
        except Exception:
            break
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            break
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        # Score: utility / max(distance, 3.6). Standard cost-utility heuristic.
        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            score = u / max(d, 3.6)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        chosen = None
        if scored:
            target_idx = scored[0][1]
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
        else:
            # No utility>0 reachable. Go to nearest unvisited node via shortest path.
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                chosen = neighbors[0]

        try:
            obs, info = env.step(chosen)
        except Exception as e:
            break
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path) as f:
                cfg = json.load(f)
            if isinstance(cfg, dict):
                episodes = cfg.get('episodes') or cfg.get('maps') or cfg.get('eval_maps') or []
            elif isinstance(cfg, list):
                episodes = cfg
        except Exception:
            episodes = []

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    if not episodes and os.path.isdir(maps_dir):
        for sub in sorted(os.listdir(maps_dir)):
            sd = os.path.join(maps_dir, sub)
            if os.path.isdir(sd):
                for fn in sorted(os.listdir(sd)):
                    if fn.lower().endswith(('.png', '.jpg', '.jpeg')):
                        episodes.append({'map_path': f'{sub}/{fn}', 'env_type': sub})

    per_episode = []
    per_type = {}
    explored_sum = 0.0
    succ_dist_sum = 0.0
    succ_count = 0
    succ_total = 0

    for ep in episodes:
        mp = ep.get('map_path') if isinstance(ep, dict) else ep
        et = ep.get('env_type') if isinstance(ep, dict) else None
        full = os.path.join(args.data_path, 'maps_eval', mp) if not os.path.isabs(mp) else mp
        if not os.path.exists(full):
            full = os.path.join(args.data_path, mp)
        if et is None:
            parts = mp.replace('\\', '/').split('/')
            et = parts[0] if len(parts) > 1 else 'unknown'
        try:
            m = plan_episode(full)
            er = float(m.get('explored_rate', 0.0))
            td = float(m.get('travel_distance', 0.0))
            sc = 1 if er > 0.9999 else 0
        except Exception as e:
            er, td, sc = 0.0, 0.0, 0
        per_episode.append({'map_path': mp, 'env_type': et, 'success': sc, 'travel_distance': td, 'explored_rate': er})
        explored_sum += er
        if sc == 1:
            succ_dist_sum += td
            succ_count += 1
        succ_total += 1
        d = per_type.setdefault(et, {'er': 0.0, 'td_succ': 0.0, 'succ': 0, 'n': 0, 'succ_n': 0})
        d['er'] += er
        d['n'] += 1
        if sc == 1:
            d['td_succ'] += td
            d['succ'] += 1
            d['succ_n'] += 1

    n = max(1, len(per_episode))
    out = {
        'explored_rate': explored_sum / n,
        'travel_distance': (succ_dist_sum / succ_count) if succ_count > 0 else 0.0,
        'success_rate': succ_count / n,
        'per_episode': per_episode,
        'per_type': {k: {'explored_rate': v['er']/max(1,v['n']), 'travel_distance': (v['td_succ']/v['succ_n']) if v['succ_n']>0 else 0.0, 'success_rate': v['succ']/max(1,v['n'])} for k, v in per_type.items()},
        'total_episodes': len(per_episode),
    }
    os.makedirs(os.path.dirname(os.path.abspath(args.output)) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(out, f)


if __name__ == '__main__':
    main()
